import{_ as t,o,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"浏览器计时","description":"","frontmatter":{},"headers":[],"relativePath":"zh/configuration/browser-timings.md","filePath":"zh/configuration/browser-timings.md"}'),r={name:"zh/configuration/browser-timings.md"};function n(c,e,s,d,l,m){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="浏览器计时" tabindex="-1"><i class="ph ph-clock-countdown"></i> 浏览器计时 <a class="header-anchor" href="#浏览器计时" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; 浏览器计时&quot;">​</a></h1><p>本页详细介绍了与 <code>Application.targetFrameRate</code> 参数相关的 WebGL 架构的技术约束。</p><p>当为 WebGL 编译 Unity 项目时，<code>Application.targetFrameRate</code> 参数不仅修改了引擎的内部帧限制，还修改了主循环运行所通过的<strong>基线浏览器 API</strong>。</p><h2 id="无上限-requestanimationframe" tabindex="-1">无上限 (requestAnimationFrame) <a class="header-anchor" href="#无上限-requestanimationframe" aria-label="Permalink to &quot;无上限 (requestAnimationFrame)&quot;">​</a></h2><p>如果您取消帧速率上限（取决于 Unity 版本，通过将 <code>Application.targetFrameRate</code> 设置为 <code>-1</code> 或 <code>0</code>），Emscripten 编译器会将 Unity 主循环直接绑定到浏览器 API <code>window.requestAnimationFrame</code>。</p><ul><li><strong>优点：</strong> 这是在网络上最原生、最流畅和最准确的渲染方法。浏览器会自动将调用与玩家显示器的刷新率 (VSync) 同步。</li><li><strong>分析：</strong> <code>cpuMainThreadFrameTime</code> 指标（由 WebAP 读取）反映了 CPU 花费在计算物理和脚本上的<strong>实际</strong>时间。</li></ul><h2 id="人为限制-settimeout" tabindex="-1">人为限制 (setTimeout) <a class="header-anchor" href="#人为限制-settimeout" aria-label="Permalink to &quot;人为限制 (setTimeout)&quot;">​</a></h2><p>如果您严格执行帧速率（例如，<code>Application.targetFrameRate = 30</code>），Emscripten将被迫放弃 <code>requestAnimationFrame</code>。相反，它利用 <code>setTimeout()</code> API 或复杂的内部计时器组合来人为地延迟循环。</p><div class="warning custom-block"><p class="custom-block-title">CPU 指标失真 (Emscripten 陷阱)</p><p>人为计时器在测量 CPU 时间时会引入严重的差异。处理器可能会在 5 毫秒内完成所有游戏逻辑计算并进入空闲状态，但 <code>WaitForEndOfFrame</code> 协程将不会恢复，直到 <code>setTimeout</code> 计时器到期。</p><p><strong>因此：</strong> <code>FrameTimingManager</code> 会将此等待时间记录到 CPU 计时中。分析器（和 WebAP 跟踪器）会推断出您遇到了 <em>CPU 瓶颈</em>，即使处理器在功能上处于空闲状态，并且帧只是在等待浏览器计时器。</p></div><h2 id="正确的配置策略" tabindex="-1">正确的配置策略 <a class="header-anchor" href="#正确的配置策略" aria-label="Permalink to &quot;正确的配置策略&quot;">​</a></h2><p>为了在浏览器中获得最佳的 Web Adaptive Performance 运行效果：</p><ol><li><strong>不要使用 <code>Application.targetFrameRate</code></strong>。将其保留为 <code>-1</code>（无上限）。</li><li>在插件设置中指定所需的 FPS（<code>Target Min FPS = 60</code>）。WebAP 不会将该值用作硬性限制，而是将其用作渲染质量决策的基础。</li></ol>',12)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
